SourceCode.Declaration:
 [DataContractAttribute]
 class EtgBankBalanceContract implements SysOperationValidatable
{
    TransDate  fromdate,todate;
}

Method.Source:
[DataMemberAttribute('From Date')]
public TransDate parmfromDate(TransDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

[DataMemberAttribute('To Date')]
public TransDate parmtoDate(TransDate _toDate = toDate)
{
    toDate = _toDate;
    return toDate;
}

public boolean validate()
{
    boolean isValid = true;

    if (!fromDate)
    {
        isValid = checkFailed("From date is required.");
    }

    if (!toDate)
    {
        isValid = checkFailed("To date is required.");
    }

    if (fromDate && toDate && fromDate > toDate)
    {
        isValid = checkFailed("From date cannot be greater than to date.");
    }

    return isValid;
}
